// RegisterTools registers all API operations as MCP tools.
func RegisterTools(s *server.MCPServer) {
	s.AddTool(
		mcplib.NewTool("message_get",
			mcplib.WithDescription("Read the message currently displayed on the board. The layout is a JSON-encoded 2D array of character codes whose dimensions depend on the board type."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/", "", true, false, nil, []mcpParamBinding{}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("message_send",
			mcplib.WithDescription("Send a new message to the board. Provide --text (plain text / VBML) or --characters (a JSON 2D array of character codes). Rate limited to 1 message per 15 seconds. Optional: text, characters, forced."),
			mcplib.WithString("body_json", mcplib.Description("Request body as a JSON object string (this endpoint accepts a polymorphic schema: oneOf/anyOf)")),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("POST", "/", "", false, false, nil, []mcpParamBinding{{PublicName: "body_json", WireName: "body_json", Location: "body_json"}}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("transition_get",
			mcplib.WithDescription("Get the current transition style and speed."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/transition", "", true, false, nil, []mcpParamBinding{}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("transition_set",
			mcplib.WithDescription("Set the transition style and speed. Both fields are required. Required: transition, transitionSpeed."),
			mcplib.WithString("transition", mcplib.Required(), mcplib.Description("Transition style: classic, wave, drift, or curtain.")),
			mcplib.WithString("transitionSpeed", mcplib.Required(), mcplib.Description("Transition speed: gentle or fast.")),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("PUT", "/transition", "", false, false, nil, []mcpParamBinding{{PublicName: "transition", WireName: "transition", Location: "body"}, {PublicName: "transitionSpeed", WireName: "transitionSpeed", Location: "body"}}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("vbml_format",
			mcplib.WithDescription("Convert a text string into a 2D array of Vestaboard character codes. Required: message. (public)"),
			mcplib.WithString("message", mcplib.Required(), mcplib.Description("The text string to format into character codes.")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("POST", "/format", "vbml", true, false, nil, []mcpParamBinding{{PublicName: "message", WireName: "message", Location: "body"}}, []string{}),
	)

	// Context tool — front-loaded domain knowledge for agents.
	// Call this first to understand the API taxonomy, query patterns, and capabilities.
	s.AddTool(
		mcplib.NewTool("context",
			mcplib.WithDescription("Get API domain context: resource taxonomy, auth requirements, query tips, and unique capabilities. Call this first."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleContext,
	)

	// Runtime Cobra-tree mirror — exposes every user-facing command that is
	// not already covered by a typed endpoint or framework MCP tool.
	cobratree.RegisterAll(s, cli.RootCmd(), cobratree.SiblingCLIPath)
}

